import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends the selected chat bubble id to the server.
 * Mirrors the server-side ChangeChatBubbleEvent packet structure.
 */
export class ChangeChatBubbleComposer implements IMessageComposer<number[]> {
    private _data: number[];

    constructor(bubbleId: number) {
        this._data = [bubbleId];
        console.log(
            `[📤] ChangeChatBubbleComposer packet sent → bubbleId ${bubbleId}`
        );
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
